const lyrics = [
  line(7.84, 'Yo no sé nadar y tú no nadas bien', 'Я не умею плавать, и ты плаваешь не очень хорошо.', 'I cannot swim, and you do not swim very well.', 'No sé + infinitivo выражает отсутствие умения; yo и tú создают параллель.', 'No sé + infinitive expresses lack of ability; yo and tú create a parallel.'),
  line(13.48, 'Y en alta mar ninguno hace pie', 'И в открытом море ни один из нас не достаёт ногами дна.', 'And in the open sea neither of us can touch the bottom.', 'En alta mar и hacer pie — устойчивые выражения.', 'En alta mar and hacer pie are fixed expressions.'),
  line(18.12, 'Pero chapotear', 'Но плескаться…', 'But splashing about…', 'Инфинитив вынесен отдельно ради ритма; мысль продолжается в следующей строке.', 'The infinitive stands alone for rhythm; the sentence continues in the next line.'),
  line(20.3, 'Y flotar sí sabemos', 'И держаться на воде мы всё-таки умеем.', 'And we do know how to float.', 'Sí после инфинитива усиливает противопоставление: это мы как раз умеем.', 'Sí adds emphatic contrast: this is something we do know how to do.'),
  line(23.2, 'Así que', 'Так что…', 'So…', 'Связка вводит результат предыдущей мысли.', 'This connector introduces the result of the previous idea.'),
  line(24.3, 'Voy a construir un velero, un bajel', 'Я построю парусник, корабль.', 'I am going to build a sailboat, a vessel.', 'Voy a + infinitivo — ближайший план; bajel добавляет поэтический оттенок.', 'Voy a + infinitive expresses a plan; bajel adds a poetic tone.'),
  line(30.96, 'Para perseguir pájaros de Portugal', 'Чтобы гнаться за птицами из Португалии.', 'To chase birds from Portugal.', 'Para + infinitivo сообщает цель действия.', 'Para + infinitive gives the purpose of the action.'),
  line(35.6, 'Y tu estela en el mar', 'И за твоим следом на море.', 'And your wake on the sea.', 'Estela — образ следа, оставленного лодкой.', 'Estela is the trail left by a boat.'),
  line(38.5, 'Y así no echarte de menos', 'И так не скучать по тебе.', 'And that way not miss you.', 'Echar de menos — неделимое выражение; te прикреплено к инфинитиву.', 'Echar de menos is a fixed phrase; te attaches to the infinitive.'),
  line(42.56, 'Y mientras navego en tu dirección', 'И пока я плыву в твоём направлении…', 'And while I sail in your direction…', 'Mientras соединяет одновременные действия.', 'Mientras links actions happening at the same time.'),
  line(47.64, 'Junto a las rocas, me aferro al timón', 'Возле скал я крепко держусь за штурвал.', 'Beside the rocks, I cling to the helm.', 'Aferrarse a требует a; a + el превращается в al.', 'Aferrarse a takes a; a + el contracts to al.'),
  line(52.28, 'Llévame, ¿a dónde?, no lo sé', 'Отвези меня — куда? Я не знаю.', 'Take me—where? I do not know.', 'Llévame — команда с прикреплённым me; no lo sé = «я этого не знаю».', 'Llévame is a command with attached me; no lo sé means “I do not know it”.'),
  line(58.0, 'A donde sea que quiera la marea', 'Куда угодно, куда захочет течение.', 'Wherever the tide may choose.', 'Неопределённость вызывает сослагательные sea и quiera.', 'Indefiniteness triggers the subjunctive forms sea and quiera.'),
  line(62.84, 'Y llévame a donde quieras, ve', 'И отвези меня куда захочешь — вперёд.', 'And take me wherever you want—go.', 'Quieras — сослагательное, ve — короткая команда от ir.', 'Quieras is subjunctive; ve is the short tú command of ir.'),
  line(67.48, 'Tú bailando y yo haciendo lo que buenamente pueda', 'Ты танцуешь, а я делаю всё, что в моих силах.', 'You dancing and me doing whatever I reasonably can.', 'Эллиптическая фраза без estamos: герундии рисуют два параллельных действия.', 'An elliptical phrase without estamos: the gerunds paint two parallel actions.'),
  line(72.04, 'Y llévame, a donde no lo sé', 'И отвези меня — куда, я не знаю.', 'And take me—where, I do not know.', 'Повтор припева; dónde подразумевает вопрос, donde — относительную связь.', 'A chorus repetition; dónde implies a question, while donde is relative.'),
  line(77.6, 'A donde sea que quiera la marea', 'Куда угодно, куда захочет течение.', 'Wherever the tide may choose.', 'Sea que quiera создаёт открытое, неопределённое направление.', 'Sea que quiera creates an open, unspecified destination.'),
  line(81.64, 'Y llévame, que yo te llevaré', 'И отвези меня — а я отвезу тебя.', 'And take me, and I will take you.', 'Te llevaré — будущее время и обещание взаимности.', 'Te llevaré is future tense and a promise of reciprocity.'),
  line(90.32, 'Yo no sé volar y tú no vuelas bien', 'Я не умею летать, и ты летаешь не очень хорошо.', 'I cannot fly, and you do not fly very well.', 'Повторяет модель первой строки; volar меняет o→ue в vuelas.', 'It mirrors the first line; volar changes o→ue in vuelas.'),
  line(95.48, 'Y por gravedad nos vamos a caer', 'И из-за гравитации мы упадём.', 'And because of gravity we are going to fall.', 'Nos vamos a caer — разговорная конструкция ближайшего будущего.', 'Nos vamos a caer is a conversational near-future construction.'),
  line(100.68, 'Si me voy a estrellar', 'Если уж я разобьюсь…', 'If I am going to crash…', 'Si без ударения вводит условие.', 'Si without an accent introduces a condition.'),
  line(104.2, 'Qué gusto hacerlo contigo', 'Как приятно сделать это с тобой.', 'What a pleasure to do it with you.', 'Qué gusto — восклицание; hacerlo и contigo — слитные формы с местоимениями.', 'Qué gusto is an exclamation; hacerlo and contigo fuse with pronouns.'),
  line(110.08, 'Llévame a lomos de un dragón', 'Унеси меня верхом на драконе.', 'Take me riding on a dragon’s back.', 'A lomos de — образное выражение «верхом на».', 'A lomos de is the figurative phrase “riding on the back of”.'),
  line(114.4, 'Acércame al sol', 'Приблизь меня к солнцу.', 'Bring me closer to the sun.', 'Команда acerca + me; al = a + el.', 'The command acerca + me; al = a + el.'),
  line(117.4, 'Rompamos el neutrón', 'Давай расщепим нейтрон.', 'Let us break the neutron.', 'Rompamos — призыв от nosotros: «давай(те) сделаем».', 'Rompamos is a nosotros “let’s” command.'),
  line(120.6, 'Y tras la explosión', 'И после взрыва…', 'And after the explosion…', 'Tras — компактный синоним después de.', 'Tras is a compact synonym of después de.'),
  line(123.2, 'En nuestro barco huimos', 'Мы спасаемся на нашей лодке.', 'We escape in our boat.', 'Huimos — форма huir для nosotros.', 'Huimos is the nosotros form of huir.'),
  line(125.88, 'Y ahora que ya estamos juntos los dos', 'И теперь, когда мы уже вдвоём…', 'And now that the two of us are finally together…', 'Ahora que вводит новую ситуацию; los dos = оба.', 'Ahora que introduces a new situation; los dos means both.'),
  line(130.56, 'Te miro, sonrío y te paso el timón', 'Я смотрю на тебя, улыбаюсь и передаю тебе штурвал.', 'I look at you, smile and hand you the helm.', 'Три формы yo соединены союзом y; te выполняет две разные объектные роли.', 'Three yo forms are joined by y; te has two object roles.'),
  line(135.44, 'Llévame, ¿a dónde?, no lo sé', 'Отвези меня — куда? Я не знаю.', 'Take me—where? I do not know.', 'Возвращение припева.', 'The chorus returns.'),
  line(141.08, 'A donde sea que quiera la marea', 'Куда угодно, куда захочет течение.', 'Wherever the tide may choose.', 'Сослагательное сохраняет ощущение неизвестности.', 'The subjunctive keeps the destination open and unknown.'),
  line(146.16, 'Y llévame a donde quieras, ve', 'И отвези меня куда захочешь — вперёд.', 'And take me wherever you want—go.', 'Команда и сослагательное стоят рядом.', 'A command and subjunctive form appear together.'),
  line(150.84, 'Tú bailando y yo haciendo lo que buenamente pueda', 'Ты танцуешь, а я делаю всё, что в моих силах.', 'You dancing and me doing whatever I reasonably can.', 'Buenamente смягчает обещание: сделать столько, сколько реально возможно.', 'Buenamente softens the promise: do as much as is reasonably possible.'),
  line(155.32, 'Y llévame (eh) a donde no lo sé', 'И отвези меня — куда, я не знаю.', 'And take me—where, I do not know.', 'Eh добавляет эмоциональный акцент к ритмическому варианту основной строки.', 'Eh adds emotional emphasis to this rhythmic variation of the main line.'),
  line(160.72, 'A donde sea que quiera la marea', 'Куда угодно, куда захочет течение.', 'Wherever the tide may choose.', 'Повтор закрепляет конструкцию a donde sea que.', 'The repetition reinforces a donde sea que.'),
  line(164.88, 'Y llévame, que yo te llevaré', 'И отвези меня — а я отвезу тебя.', 'And take me, and I will take you.', 'Llevaré — простое будущее.', 'Llevaré is simple future.'),
  line(171.2, 'Uh-uh-uh, uh-uh-uh', 'Вокализация.', 'Vocalization.', 'Ритмический фрагмент без лексического значения.', 'A rhythmic section without lexical meaning.'),
  line(176.0, 'Uh-uh-uh-uh-uh', 'Вокализация.', 'Vocalization.', 'Можно использовать для повторения мелодии перед финальным припевом.', 'Use it to internalize the melody before the final chorus.'),
  line(181.0, 'Uh-uh-uh, uh-uh-uh', 'Вокализация.', 'Vocalization.', 'Лексики нет; только ритм и дыхание.', 'No vocabulary here; only rhythm and breath.'),
  line(186.0, 'Uh-uh-uh-uh-uh (eh)', 'Вокализация и возглас.', 'Vocalization and exclamation.', 'Eh добавляет разговорный эмоциональный акцент.', 'Eh adds an informal emotional accent.'),
  line(192.16, 'Llévame, ¿a dónde?, no lo sé', 'Отвези меня — куда? Я не знаю.', 'Take me—where? I do not know.', 'Финальный припев начинается с главной команды песни.', 'The final chorus begins with the song’s central command.'),
  line(197.6, 'A donde sea que quiera la marea', 'Куда угодно, куда захочет течение.', 'Wherever the tide may choose.', 'Море и течение остаются метафорой неизвестного пути.', 'The sea and tide remain a metaphor for an unknown path.'),
  line(201.48, 'Y llévame y yo te llevaré (eh)', 'И отвези меня, а я отвезу тебя.', 'And take me, and I will take you.', 'Две стороны обещают поддерживать друг друга.', 'Both sides promise to carry and support each other.'),
  line(204.04, 'Tú bailando y yo haciendo lo que buenamente pueda', 'Ты танцуешь, а я делаю всё, что в моих силах.', 'You dancing and me doing whatever I reasonably can.', 'Название песни Haré lo que pueda развивает ту же идею: «сделаю всё, что смогу».', 'The title Haré lo que pueda develops the same idea: “I will do what I can”.'),
  line(210.64, 'Y llévame y yo te llevaré (eh)', 'И отвези меня, а я отвезу тебя.', 'And take me, and I will take you.', 'Повтор обещания взаимности.', 'The mutual promise repeats.'),
  line(214.8, 'Ay-ay-ay-ay-ay', 'Эмоциональная вокализация.', 'Emotional vocalization.', 'Ay передаёт эмоцию, но здесь не требует буквального перевода.', 'Ay conveys emotion but has no literal translation here.'),
  line(217.84, 'Llévame (llévame) y yo te llevaré', 'Отвези меня — отвези — а я отвезу тебя.', 'Take me—take me—and I will take you.', 'Финальная строка соединяет команду и обещание в будущем времени.', 'The final line joins a command with a future promise.'),
]

